import React, { useState } from "react";
import Cookies from "js-cookie";
import { useNavigate } from "react-router-dom";

function AdminLogin() {
  const [phoneNumber, setPhoneNumber] = useState("");
  const [otp, setOtp] = useState("");
  const [otpSent, setOtpSent] = useState(false);
  const [success, setSuccess] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const API_BASE_URL = "http://localhost:5000"; // Change this to your API URL

  // ---------- SEND OTP ----------
  async function handleSendOtp(e) {
    e.preventDefault();

    if (!/^\d{10}$/.test(phoneNumber)) {
      setError("Phone number must be 10 digits");
      return;
    }

    setLoading(true);
    setError("");
    setSuccess("");

    try {
      const response = await fetch(`${API_BASE_URL}/admin/send-otp`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ phone: phoneNumber }),
      });

      const data = await response.json();

      if (response.ok && data.status) {
        setOtpSent(true);
        setSuccess("OTP sent successfully! Check your console/SMS");
      } else {
        setError(data.error || "Failed to send OTP");
      }
    } catch (err) {
      console.error(err);
      setError("Server error while sending OTP");
    }

    setLoading(false);
  }

  // ---------- VERIFY OTP ----------
  async function handleVerifyOtp(e) {
    e.preventDefault();

    if (!/^\d{6}$/.test(otp)) {
      setError("OTP must be 6 digits");
      return;
    }

    setLoading(true);
    setError("");
    setSuccess("");

    try {
      const response = await fetch(`${API_BASE_URL}/admin/verify-otp`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ phone: phoneNumber, otp }),
      });

      const data = await response.json();

      if (response.ok && data.status) {
        Cookies.set("adminToken", data.token, { expires: 7 });
        Cookies.set("adminPhoneNumber", phoneNumber, { expires: 7 });

        setSuccess("Logged in Successfully!");
        setTimeout(() => navigate("/users"), 800);
      } else {
        setError(data.error || "Invalid OTP");
      }
    } catch (err) {
      console.error(err);
      setError("Server error while verifying OTP");
    }

    setLoading(false);
  }

  return (
    <div className="container d-flex flex-column align-items-center justify-content-center min-vh-100">
      <img
        loading="lazy"
        className="img-fluid mb-4"
        style={{ width: "220px", height: "auto" }}
        src="https://equitypandit.in/ep-imgs/ep-advisor-logo.svg"
        alt="EP-Investment-Advisor"
      />

      <div
        className="card shadow-md border-0 rounded p-4"
        style={{ maxWidth: "450px", width: "100%" }}
      >
        <div className="card-body">
          <h2 className="text-center fw-bold text-dark mb-4">Admin Login</h2>

          {success && <div className="alert alert-success">{success}</div>}
          {error && <div className="alert alert-danger">{error}</div>}

          {!otpSent ? (
            <form onSubmit={handleSendOtp}>
              <div className="mb-4">
                <label className="form-label fw-semibold">Phone Number</label>
                <input
                  type="text"
                  className="form-control"
                  value={phoneNumber}
                  onChange={(e) => setPhoneNumber(e.target.value)}
                  placeholder="Enter 10-digit phone number"
                  required
                />
              </div>
              <button
                type="submit"
                className="btn btn-success w-100"
                disabled={loading}
              >
                {loading ? "Sending..." : "Send OTP"}
              </button>
            </form>
          ) : (
            <form onSubmit={handleVerifyOtp}>
              <div className="mb-4">
                <label className="form-label fw-semibold">6-digit OTP</label>
                <input
                  type="text"
                  className="form-control"
                  value={otp}
                  onChange={(e) => setOtp(e.target.value)}
                  placeholder="Enter OTP"
                  required
                />
              </div>
              <button
                type="submit"
                className="btn btn-success w-100"
                disabled={loading}
              >
                {loading ? "Verifying..." : "Verify OTP"}
              </button>
            </form>
          )}
        </div>
      </div>
    </div>
  );
}

export default AdminLogin;
